import React, { useEffect, useMemo, useRef, useState } from 'react';
import {
  ActivityIndicator,
  Alert,
  Button,
  SafeAreaView,
  ScrollView,
  StyleSheet,
  Text,
  View,
  Linking,
  Platform,
} from 'react-native';

const OAUTH = {
  authorizationEndpoint: 'https://auth.example.com/oauth/authorize',
  tokenEndpoint: 'https://auth.example.com/oauth/token',
  clientId: 'mobile_app_client_123',
  clientSecret: undefined,
  redirectUri: Platform.select({
    ios: 'com.example.app://oauth/callback',
    android: 'com.example.app://oauth/callback',
    default: 'com.example.app://oauth/callback',
  }),
  scope: 'openid profile email offline_access',
  responseType: 'code',
  usePkce: true,
};

function base64UrlEncode(bytes) {
  let binary = '';
  for (let i = 0; i < bytes.length; i += 1) binary += String.fromCharCode(bytes[i]);
  return btoa(binary).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/g, '');
}

function randomString(length = 64) {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  let out = '';
  const array = new Uint8Array(length);
  if (global.crypto?.getRandomValues) {
    global.crypto.getRandomValues(array);
    for (let i = 0; i < array.length; i += 1) out += chars[array[i] % chars.length];
    return out;
  }
  for (let i = 0; i < length; i += 1) out += chars[Math.floor(Math.random() * chars.length)];
  return out;
}

async function sha256(input) {
  const encoder = new TextEncoder();
  const data = encoder.encode(input);
  if (global.crypto?.subtle?.digest) {
    const hash = await global.crypto.subtle.digest('SHA-256', data);
    return new Uint8Array(hash);
  }
  throw new Error('SHA-256 not supported on this platform');
}

async function createPkcePair() {
  const verifier = randomString(96);
  const hash = await sha256(verifier);
  const challenge = base64UrlEncode(hash);
  return { verifier, challenge };
}

function buildAuthorizeUrl({ state, codeChallenge }) {
  const params = new URLSearchParams({
    response_type: OAUTH.responseType,
    client_id: OAUTH.clientId,
    redirect_uri: OAUTH.redirectUri,
    scope: OAUTH.scope,
    state,
  });
  if (OAUTH.usePkce) {
    params.set('code_challenge', codeChallenge);
    params.set('code_challenge_method', 'S256');
  }
  return `${OAUTH.authorizationEndpoint}?${params.toString()}`;
}

async function exchangeCodeForTokens({ code, codeVerifier }) {
  const body = new URLSearchParams({
    grant_type: 'authorization_code',
    code,
    redirect_uri: OAUTH.redirectUri,
    client_id: OAUTH.clientId,
  });

  if (OAUTH.usePkce) {
    body.set('code_verifier', codeVerifier);
  } else if (OAUTH.clientSecret) {
    body.set('client_secret', OAUTH.clientSecret);
  }

  const response = await fetch(OAUTH.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      Accept: 'application/json',
    },
    body: body.toString(),
  });

  const json = await response.json().catch(() => ({}));
  if (!response.ok) {
    throw new Error(json.error_description || json.error || `Token exchange failed (${response.status})`);
  }
  return json;
}

export default function App() {
  const [loading, setLoading] = useState(false);
  const [authUrl, setAuthUrl] = useState('');
  const [tokens, setTokens] = useState(null);
  const [status, setStatus] = useState('Ready');
  const authStateRef = useRef(null);
  const pkceRef = useRef(null);

  useEffect(() => {
    const handleUrl = async (event) => {
      try {
        const url = event.url;
        if (!url.startsWith(OAUTH.redirectUri)) return;

        const parsed = new URL(url);
        const code = parsed.searchParams.get('code');
        const state = parsed.searchParams.get('state');
        const error = parsed.searchParams.get('error');
        const errorDescription = parsed.searchParams.get('error_description');

        if (error) {
          throw new Error(errorDescription || error);
        }
        if (!code) {
          throw new Error('Authorization code not found');
        }
        if (!state || state !== authStateRef.current) {
          throw new Error('Invalid state parameter');
        }

        setLoading(true);
        setStatus('Exchanging code for tokens...');
        const tokenResponse = await exchangeCodeForTokens({ code, codeVerifier: pkceRef.current?.verifier });
        setTokens(tokenResponse);
        setStatus('Authenticated');
      } catch (err) {
        setStatus('Authentication failed');
        Alert.alert('OAuth Error', err.message || 'Unknown error');
      } finally {
        setLoading(false);
      }
    };

    const subscription = Linking.addEventListener('url', handleUrl);
    Linking.getInitialURL().then((url) => {
      if (url) handleUrl({ url });
    });

    return () => subscription.remove();
  }, []);

  const startLogin = async () => {
    try {
      setLoading(true);
      setStatus('Preparing authorization request...');
      const state = randomString(32);
      authStateRef.current = state;
      const pkce = await createPkcePair();
      pkceRef.current = pkce;
      const url = buildAuthorizeUrl({ state, codeChallenge: pkce.challenge });
      setAuthUrl(url);
      setStatus('Opening browser...');
      const supported = await Linking.canOpenURL(url);
      if (!supported) throw new Error('Cannot open authorization URL');
      await Linking.openURL(url);
    } catch (err) {
      setStatus('Ready');
      Alert.alert('Login Error', err.message || 'Unknown error');
      setLoading(false);
    }
  };

  const signOut = () => {
    setTokens(null);
    setStatus('Signed out');
    authStateRef.current = null;
    pkceRef.current = null;
  };

  const tokenText = useMemo(() => {
    if (!tokens) return 'No tokens yet';
    return JSON.stringify(tokens, null, 2);
  }, [tokens]);

  return (
    <SafeAreaView style={styles.container}>
      <ScrollView contentContainerStyle={styles.content}>
        <Text style={styles.title}>OAuth 2.0 Mobile App</Text>
        <Text style={styles.label}>Status</Text>
        <Text style={styles.value}>{status}</Text>

        <View style={styles.section}>
          <Button title="Login with OAuth" onPress={startLogin} disabled={loading} />
        </View>

        <View style={styles.section}>
          <Button title="Sign Out" onPress={signOut} disabled={loading || !tokens} />
        </View>

        {loading ? (
          <View style={styles.section}>
            <ActivityIndicator size="large" />
          </View>
        ) : null}

        <Text style={styles.label}>Authorization URL</Text>
        <Text selectable style={styles.mono}>
          {authUrl || 'Not started'}
        </Text>

        <Text style={styles.label}>Tokens</Text>
        <Text selectable style={styles.mono}>
          {tokenText}
        </Text>
      </ScrollView>
    </SafeAreaView>
  );
}

